import{_ as s,o as e,c as t,a2 as n}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"伤害计算","description":"","frontmatter":{},"headers":[],"relativePath":"guide/damage.md","filePath":"guide/damage.md","lastUpdated":1781102744000}'),i={name:"guide/damage.md"};function p(l,a,d,o,c,h){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="伤害计算" tabindex="-1">伤害计算 <a class="header-anchor" href="#伤害计算" aria-label="Permalink to &quot;伤害计算&quot;">​</a></h1><h2 id="六乘区模型" tabindex="-1">六乘区模型 <a class="header-anchor" href="#六乘区模型" aria-label="Permalink to &quot;六乘区模型&quot;">​</a></h2><p>FunGame 的伤害计算分为 <strong>6 个乘区</strong>，按以下顺序计算：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 基础伤害倍率</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>② 伤害加成区间 1</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>③ 减伤</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>④ 暴击伤害区间</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>⑤ 伤害加成区间 2</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>⑥ 魔法效能（仅魔法技能）</span></span></code></pre></div><h3 id="_1-基础伤害倍率" tabindex="-1">① 基础伤害倍率 <a class="header-anchor" href="#_1-基础伤害倍率" aria-label="Permalink to &quot;① 基础伤害倍率&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础伤害 = 基础伤害基底 × 基础伤害倍率</span></span></code></pre></div><p>例如普通攻击基于 100% 攻击力，则取攻击力的数值 × 100%。</p><h3 id="_2-伤害加成区间-1" tabindex="-1">② 伤害加成区间 1 <a class="header-anchor" href="#_2-伤害加成区间-1" aria-label="Permalink to &quot;② 伤害加成区间 1&quot;">​</a></h3><ul><li><strong>固定值加成</strong>：直接加法 <code>基础伤害 + 100</code></li><li><strong>百分比加成</strong>：<code>基础伤害 × (1 + 所有百分比之和)</code></li></ul><div class="tip custom-block"><p class="custom-block-title">示例</p><p>两个技能分别提供 30% 和 70% 加成： <code>基础伤害 × (1 + (30% + 70%)) = 基础伤害 × 2</code></p></div><h3 id="_3-减伤" tabindex="-1">③ 减伤 <a class="header-anchor" href="#_3-减伤" aria-label="Permalink to &quot;③ 减伤&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础伤害 = 基础伤害 × (1 - 减伤%)</span></span></code></pre></div><p>若目标减伤为 20%：<code>基础伤害 = 基础伤害 × 0.8</code></p><h3 id="_4-暴击伤害区间" tabindex="-1">④ 暴击伤害区间 <a class="header-anchor" href="#_4-暴击伤害区间" aria-label="Permalink to &quot;④ 暴击伤害区间&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基础伤害 = 基础伤害 × 暴击伤害倍率</span></span></code></pre></div><h3 id="_5-伤害加成区间-2" tabindex="-1">⑤ 伤害加成区间 2 <a class="header-anchor" href="#_5-伤害加成区间-2" aria-label="Permalink to &quot;⑤ 伤害加成区间 2&quot;">​</a></h3><p>计算方式同区间 1。</p><h3 id="_6-魔法效能" tabindex="-1">⑥ 魔法效能 <a class="header-anchor" href="#_6-魔法效能" aria-label="Permalink to &quot;⑥ 魔法效能&quot;">​</a></h3><p>仅魔法技能应用此乘区，详见技能系统 → 魔法。</p><hr><h2 id="物理伤害计算" tabindex="-1">物理伤害计算 <a class="header-anchor" href="#物理伤害计算" aria-label="Permalink to &quot;物理伤害计算&quot;">​</a></h2><p>以普通攻击为例的完整流程：</p><h3 id="_1-预计伤害" tabindex="-1">1. 预计伤害 <a class="header-anchor" href="#_1-预计伤害" aria-label="Permalink to &quot;1. 预计伤害&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(基础攻击力 + 附加攻击力) × 伤害系数</span></span></code></pre></div><h3 id="_2-物理穿透" tabindex="-1">2. 物理穿透 <a class="header-anchor" href="#_2-物理穿透" aria-label="Permalink to &quot;2. 物理穿透&quot;">​</a></h3><p>削减目标的物理护甲。角色穿透 30%，目标护甲 60：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1 - 0.3) × 60 = 42 （实际护甲）</span></span></code></pre></div><h3 id="_3-物理伤害减免" tabindex="-1">3. 物理伤害减免 <a class="header-anchor" href="#_3-物理伤害减免" aria-label="Permalink to &quot;3. 物理伤害减免&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>物理伤害减免 = 护甲 / (护甲 + 240) × 100%</span></span></code></pre></div><p>接上例：<code>42 / (42 + 240) = 14.89%</code></p><h3 id="_4-最终物理伤害" tabindex="-1">4. 最终物理伤害 <a class="header-anchor" href="#_4-最终物理伤害" aria-label="Permalink to &quot;4. 最终物理伤害&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>预计伤害 × (1 - 物理伤害减免)</span></span></code></pre></div><hr><h2 id="魔法伤害计算" tabindex="-1">魔法伤害计算 <a class="header-anchor" href="#魔法伤害计算" aria-label="Permalink to &quot;魔法伤害计算&quot;">​</a></h2><p>与物理伤害类似：</p><table tabindex="0"><thead><tr><th>物理</th><th>魔法</th></tr></thead><tbody><tr><td>物理伤害减免</td><td>魔法抗性</td></tr><tr><td>物理穿透</td><td>魔法穿透</td></tr><tr><td>护甲 → 减免转换</td><td>穿透直接作用于抗性</td></tr></tbody></table><p>魔法伤害具有属性，不同属性应用不同魔法抗性，但魔法穿透为共用属性。</p>`,37)])])}const b=s(i,[["render",p]]);export{u as __pageData,b as default};
